"""
MKT Context Commentary — 2 Chronicles 25–28 PATCH
Fills the 79 verses missed by the original stub script.
Run: python3 scripts/zc-context-2chronicles-25-28-patch.py
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PATCH = {
  "25": {
    "1": "<p>Amaziah accedes at age 25 and reigns 29 years in Jerusalem. His mother Jehoaddan is from Jerusalem — her name (YHWH delights) suggests a devout family. The reign length of 29 years places his accession c. 796 BCE and death c. 767 BCE, overlapping substantially with Jehoash of Israel (c. 798–782). The Chronicler's evaluation formula adds the unusual qualifier 'but not with a whole heart' (<em>wᵉlōʾ bᵉlēḇāḇ šālēm</em>), which appears already in v. 2 as an editorial note — a preview of the double-mindedness the chapter will dramatize in the Edomite gods episode.</p>",
    "2": "<p>The evaluation 'he did what was right in the eyes of YHWH, but not with a whole heart' (<em>lēḇāḇ šālēm</em>) is the Chronicler's signature moral category, used also of Amaziah's ancestor Asa (15:17). Wholeness of heart (<em>šlm</em>) is a Deuteronomic covenant loyalty term; its absence flags compromised devotion rather than apostasy. The Chronicler signals from the outset that Amaziah is a divided figure — capable of correct behavior but susceptible to the syncretism that will doom his reign.</p>",
    "3": "<p>Amaziah's execution of his father's assassins (Jozabad and Jehozabad; cf. 24:25-26) is a standard succession legitimation act in ancient Near Eastern royal practice. Eliminating political threats while consolidating power is documented across Mesopotamian and Egyptian succession accounts. The Chronicler notes the act matter-of-factly; its political necessity is assumed. The named assassins are Moabite/Ammonite in ancestry (as 2 Kgs 12:21 specifies), which may carry covenantal significance — foreign influence reaching into the palace guard.</p>",
    "4": "<p>The explicit citation of Deuteronomy 24:16 ('fathers shall not die for children; each one shall die for his own sin') is rare in Chronicles — a direct quotation establishing that Amaziah's restraint derives from Torah law, not political calculation. The law in view (<em>ʾîš bᵉḥeṭʾô yāmûtû</em>) is a procedural limit on punitive justice: collective punishment of families is forbidden. This Deuteronomic principle stands in tension with the Decalogue's 'visiting iniquity to the third and fourth generation' (Ex 20:5) — rabbinic tradition reconciled these by limiting collective punishment to those who replicate ancestral sins.</p>",
    "5": "<p>Amaziah's military census produces 300,000 select troops from Judah and Benjamin — a plausible standing force for an 8th-century Judahite kingdom with significant territorial extent. The mustering unit (<em>ʾelep</em> = 1,000 or perhaps a military sub-unit) is the standard census format (cf. 2 Chr 14:8; 17:14-18). The troop designation <em>gibbôrê ḥayil</em> (mighty men of valor) identifies professional soldiers capable of handling spear and shield, distinguished from conscript levies. Benjamin's inclusion in the southern muster (rather than northern) is a consistent Chronicler pattern reflecting the post-schism alignment of Benjamin with Judah.</p>",
    "6": "<p>Amaziah's hire of 100,000 Israelite mercenaries for 100 talents of silver reflects standard Iron Age military practice: regional powers leased troops between campaigns. The rate of one talent per thousand soldiers is comparable to documented mercenary rates in Neo-Assyrian records. The hire of northern Israelite troops creates an implicit religious problem: the northern kingdom's syncretic worship (golden calves, unauthorized shrines) means associating with an army YHWH has abandoned — the theological logic the unnamed prophet will articulate in vv. 7-9.</p>",
    "7": "<p>The 'man of God' (<em>ʾîš hāʾĕlōhîm</em>) who warns against using Israelite troops invokes the principle of holy war purity: YHWH is not with Ephraim (<em>ʾên YHWH ʿim-yiśrāʾēl</em>). The northern kingdom's apostasy has rendered its armies ritually incompatible with a YHWH-sanctioned campaign. The concept parallels Deuteronomy's holy war laws (Deut 20) and the Chronicler's consistent pattern of military outcomes tracking covenant fidelity. The prophet's warning is not about military effectiveness but about whose god is fighting — mixing forces means mixing allegiances.</p>",
    "8": "<p>The prophet's statement 'but if you do go, act and be strong for the battle; but God will cause you to fall before the enemy' is a conditional oracle of doom: Amaziah may proceed with the mercenaries, but the outcome is predetermined. The formulation highlights divine sovereignty over military outcomes regardless of troop numbers. The Chronicler's interest is not pacifism but the theology of dependence on YHWH: strength of arms without divine backing is self-defeating. The same principle structures the Chronicler's accounts of David (1 Chr 22:13), Jehoshaphat (20:17), and Asa (14:11).</p>",
    "9": "<p>Amaziah's practical question — what about the 100 talents of silver I paid the mercenaries? — is a humanizing detail showing realistic royal decision-making. The prophet's response is theologically programmatic: 'YHWH is able to give you much more than this' (<em>yēš bêYHWH lātēt lᵉkā harbēh mizzeh</em>). The exchange establishes that economic risk is no grounds for disobeying prophetic guidance. The pattern recurs in the Chronicler's theology of wealth: obedience yields divine surplus that exceeds what disobedience could purchase (cf. 2 Chr 31:10; 2 Cor 9:8).</p>",
    "10": "<p>Amaziah's dismissal of the Israelite mercenaries triggers their 'great anger' (<em>wayyiḥar ʾappām bimᵉʾōd</em>): soldiers who have been hired, armed, and then sent home without combat — and presumably without full pay for the campaign — have lost both income and honor. The mercenaries' subsequent raid on Judahite cities (v. 13: 3,000 killed, significant plunder) is the unintended collateral consequence of Amaziah's obedience. The episode shows that covenant obedience does not eliminate earthly consequences — the dismissed mercenaries became an autonomous military threat that the text does not present as divine punishment but as realpolitik blowback.</p>",
    "12": "<p>The execution of 10,000 Edomite prisoners by throwing them from a cliff (<em>hasselaʿ</em>) is a documented ancient Near Eastern practice for handling large captive populations when enslavement or ransom is impractical. Assyrian reliefs (notably at Nimrud and Nineveh) depict impaled or cliff-executed prisoners. The Hebrew <em>sela</em> can mean 'rock/cliff' generally or the specific site Sela (later Petra) in Edom's heartland. If the latter, the execution at Sela carries symbolic weight: Amaziah destroys Edomites at their own capital stronghold. The scale (10,000) matches the victory total in v. 11, suggesting all prisoners were executed rather than enslaved.</p>",
    "13": "<p>The mercenaries Amaziah dismissed raided the cities of Judah from Samaria to Beth-horon, killing 3,000 and taking plunder (<em>baz</em>). Beth-horon marks the traditional border between Benjamin and Ephraim — the mercenaries operated in the northern borderland, which they could access without deep penetration of Judahite territory. The phrase 'from Samaria to Beth-horon' may indicate a sweep along the border region rather than a route — traveling southward from Israelite territory and raiding as far as the pass. The episode demonstrates that Amaziah's obedience to prophetic guidance incurred a real military liability; the text does not moralize the loss but presents it as a consequence of the dismissal.</p>",
    "15": "<p>YHWH's anger (<em>wayyiḥar-ʾaf YHWH bᵉʾamasyāhû</em>) at Amaziah's Edomite-god worship sets up the prophetic confrontation of v. 15b. The messenger's question — 'Why have you sought the gods of a people who did not deliver their own people from your hand?' — is a sharp piece of theological logic: Amaziah defeated Edom (their gods failed to protect them), so adopting those same defeated gods is a category error. The argument corresponds to the ANE theology of divine power-by-military-proxy: gods whose armies lose are gods who failed. The Chronicler uses Amaziah's episode as a case study in irrational syncretism — choosing the losing god of a conquered enemy.</p>",
    "16": "<p>Amaziah's silencing of the prophet — 'Have we made you royal counselor? Stop! Why should you be struck down?' — is an assertion of royal prerogative over prophetic speech. The threat 'why should you be struck down?' (<em>lāmmāh yaḵûkā</em>) implies the prophet faces royal violence for speaking. The prophet's cryptic response — 'I know that God has determined to destroy you' — is a classic prophetic irony: Amaziah refuses counsel and thereby confirms the judgment the counsel was warning against. The pattern repeats the dynamic of 2 Chr 18:12-16 (Micaiah) and 24:20-22 (Zechariah) — royal rejection of prophetic counsel as the hinge on which doom turns.</p>",
    "17": "<p>Amaziah's challenge to Jehoash of Israel for a face-to-face meeting (<em>nitrāʾeh pānîm</em>) is a formal declaration of inter-state hostilities. The phrase is used elsewhere for hostile military encounter (2 Kgs 14:8, 11; 23:29). Amaziah's hubris after the Edomite campaign — success that the narrative has already attributed to YHWH's grace rather than Amaziah's strength — leads him to pick a fight with the northern kingdom for reasons the text does not explain. The move is a classic tragic pattern: military success in a legitimate war (Edom) breeds overconfidence for an illegitimate war (Israel).</p>",
    "18": "<p>Jehoash's fable of the thistle and cedar of Lebanon (<em>ḥôaḥ</em> and <em>ʾerez</em>) is a concise piece of political wisdom literature — a <em>māšāl</em> (parable) genre used in diplomatic correspondence. The thistle asks the cedar for its daughter in marriage; a wild beast tramples the thistle. The analogy is transparent: Amaziah (thistle) seeks to dominate Jehoash (cedar) but will be crushed. Jehoash frames the parable as advice: 'Stay home! Why provoke disaster?' The genre of diplomatic fable has parallels in Akkadian wisdom literature (the fable of the fox and the wolf in the Sumerian literary tradition) and in Judges 9:8-15 (Jotham's parable of the trees choosing a king).</p>",
    "19": "<p>Jehoash's diagnosis — 'you say to yourself that you have struck down Edom, and your heart has lifted you up in pride' — names the spiritual mechanism behind Amaziah's aggression: <em>gāḇah lēḇᵉkā</em> (your heart has been exalted/lifted high). The word group <em>gāḇah / gābah</em> is the Chronicler's signature pride vocabulary, used for Uzziah's fall (26:16), Hezekiah's initial error (32:25), and the pattern of royal hubris generally. Pride (<em>gaʾăwāh</em>) is the theological mechanism by which military success becomes the seed of destruction. Jehoash's counsel to 'stay at home' rather than provoke trouble recognizes that Judah lacks the military capacity to defeat Israel in open battle.</p>",
    "20": "<p>The Chronicler's explanation that Amaziah 'did not listen, for it was from God, in order that he might give them into the hand of their enemies' (<em>mēhāʾĕlōhîm hîʾ lᵉmaʿan tittām bᵉyad ʾōyᵉḇêhem</em>) is a divine causation formula for covenantal judgment. God's purposes are accomplished through the king's own pride-driven bad decisions: there is no external divine compulsion, only the self-determining logic of human arrogance working itself out. The same formula governs Rehoboam's refusal to listen (10:15) and the hardening narrative in Exodus. It represents the Chronicler's mature theology of retribution: divine judgment operates through natural human choices, not arbitrary divine manipulation.</p>",
    "21": "<p>The battle at Beth-shemesh — a significant Iron Age city in the Shephelah guarding the Sorek Valley approach to Jerusalem — is a geopolitically telling location for a Judah-Israel engagement. Beth-shemesh controls the major western access corridor to Judah; Jehoash's victory there would have given him a clear route to Jerusalem. Archaeological excavations at Tel Batash (Timnah) and Tel Bet-Shemesh have produced Iron IIb destruction layers that may correspond to this period. That the battle occurs at Beth-shemesh (Judahite territory) rather than on the border indicates Amaziah's forces had already advanced northward and were met coming back — or that Jehoash pursued south.</p>",
    "22": "<p>Judah is 'struck down' (<em>wayyinnāgep yᵉhûdāh</em>) before Israel — the same technical verb used for decisive military defeat in holy war accounts (cf. 1 Chr 14:11 — God 'struck down my enemies'). The reversal is pointed: the same word used for YHWH's victories now describes Judah's humiliation at Israelite hands. Each man fled to his own home is the formulaic rout description (1 Kgs 22:36; 2 Chr 18:16), marking total military collapse rather than orderly retreat.</p>",
    "23": "<p>Jehoash took Amaziah prisoner at Beth-shemesh and brought him to Jerusalem, then broke down 400 cubits of the northern wall of Jerusalem (from the Ephraim Gate to the Corner Gate). The wall breach is a standard ancient Near Eastern submission gesture — rendering a conquered city defenseless without destroying it. The 400-cubit gap (~180 meters) would have eliminated a significant section of the northern defenses, the most militarily important face since Jerusalem's topography protects the south and west. The Ephraim Gate (facing north toward Ephraim) and the Corner Gate appear together in Neh 8:16; Jer 31:38, marking the northwestern defensive perimeter.</p>",
    "24": "<p>Jehoash plundered the Jerusalem temple treasury and palace treasury, taking gold, silver, vessels (<em>kēlîm</em>), and hostages (<em>bᵉnê hattaʿărūḇôt</em>) back to Samaria. The taking of hostages as security against future rebellion is documented in Neo-Assyrian treaties and in Egyptian campaign records. Temple treasuries served as state reserve funds throughout the Iron Age; multiple Judahite kings used them for tribute payments (cf. Asa in 16:2; Ahaz in 28:21; Hezekiah in 2 Kgs 18:15-16). The plundering of the Jerusalem sanctuary by the northern kingdom reverses the theological logic of the schism — the legitimate cult site is ransacked by the apostate north.</p>",
    "25": "<p>Amaziah outlives Jehoash by 15 years, but this survival is now contaminated by his defeat and the conspiracy that will eventually end his reign. The 15-year period after defeat (c. 782–767 BCE if Amaziah died c. 767) matches the Assyrian Eponym Chronicle's dating roughly, though the Judahite chronology of this period is contested. The Chronicler notes the survival matter-of-factly; the judgment against Amaziah's reign has already been pronounced through the military catastrophe.</p>",
    "26": "<p>The conspiracy (<em>qešer</em>) against Amaziah in Jerusalem — he flees to Lachish but is sent after and killed there — mirrors the assassination of his own father Joash (24:25-26), who was also killed by conspirators. The flight to Lachish (a major fortress city 25 miles southwest of Jerusalem in the Shephelah) shows Amaziah seeking refuge in a fortified city rather than the capital; Lachish is the second city of Judah in the Iron IIb period and the site of Sennacherib's famous siege (2 Chr 32; 2 Kgs 18-19). The conspirators pursue him there — the flight itself is not enough to escape a determined palace coup.</p>",
    "27": "<p>Amaziah is buried in the city of Judah (<em>ʿîr yᵉhûdāh</em>) — which likely means Lachish or possibly Jerusalem. The ambiguity may reflect textual corruption or a non-standard burial location. His son Uzziah (also called Azariah) is made king at age 16, indicating Amaziah was still relatively young at death (29-year reign beginning at age 25 = death at 54). The succession at 16 could mean Uzziah was the son of a secondary wife rather than the principal queen, or that Amaziah's primary heir had died during the years of military disaster.</p>",
    "28": "<p>All the acts of Amaziah from first to last are written in the Book of the Kings of Judah and Israel (<em>sēper malᵉḵê yᵉhûdāh wᵉyiśrāʾēl</em>). The double-named source document — Kings of Judah and Israel rather than Kings of Israel and Judah — is the southern perspective source the Chronicler cites throughout. The Chronicler's selective use of this source omits political and diplomatic details preserved in 2 Kings 14 in favor of the theological narrative of obedience, pride, and judgment.</p>"
  },
  "26": {
    "1": "<p>All the people of Judah take Uzziah (also called Azariah in 2 Kings 14-15) at age 16 and make him king in place of his father Amaziah. The popular installation formula (<em>wayyiqḥû kol-ʿam yᵉhûdāh</em>) appears in succession crises where the royal court affirms a young or unexpected heir; cf. 2 Chr 36:1 (Jehoahaz), 33:25 (Josiah). Uzziah's two names (Uzziah = 'YHWH is my strength'; Azariah = 'YHWH has helped') appear to be in use simultaneously in different sources, which explains the apparent discrepancy between Chronicles and Kings — different court scribes may have preferred different throne names.</p>",
    "2": "<p>Uzziah rebuilds Eloth (Elath, on the Gulf of Aqaba) and restores it to Judah after Amaziah's death — an act of territorial recovery confirming the Chronicler's interest in the Red Sea port, which David controlled (1 Chr 18:12) and Solomon used for the Ophir fleet (2 Chr 9:21). Archaeological work at Tell el-Kheleifeh (Ezion-geber) has recovered Iron IIb strata corresponding to this period. Control of Elath gave Judah access to Arabian trade routes and the Red Sea maritime network; losing Elath (as happens in 2 Kgs 16:6 under Ahaz) marks the end of Judahite commercial reach to the south.</p>",
    "3": "<p>Uzziah's 52-year reign (c. 792–740 BCE, including a possible co-regency with Amaziah) is the longest reign in Judah's history. The chronology is complex: if Uzziah began reigning at 16 and reigned 52 years, he died at 68. The co-regency hypothesis (Uzziah as co-regent from c. 792, full reign from c. 767 after Amaziah's assassination) reconciles the long reign with the overall Judahite chronology and the synchronisms with northern kings. His mother Jecoliah is from Jerusalem — palace family continuity from Amaziah's line.</p>",
    "4": "<p>Uzziah's evaluation — 'he did what was right in the eyes of YHWH, according to all that his father Amaziah had done' — is carefully hedged: Amaziah's mixed record (v. 2 of ch. 25: 'but not with a whole heart') is the template. The Chronicler does not evaluate Uzziah positively in the unqualified terms he reserves for David, Hezekiah, or Josiah. The high places continued, as the parallel note in 2 Kgs 15:4 specifies — the same limitation the Chronicler regularly applies to reform kings who did not complete the cultic centralization program.</p>",
    "5": "<p>Zechariah's role as Uzziah's prophetic mentor — 'who had understanding through the visions of God' (<em>hammēḇîn birᵉʾôt hāʾĕlōhîm</em>) — establishes a prophetic guidance framework for Uzziah's success. The formula 'as long as he sought YHWH, God made him prosper' (<em>bᵉdārᵉšô ʾet-YHWH hiṣlîḥô hāʾĕlōhîm</em>) is the Chronicler's core retribution principle in concentrated form. This Zechariah (not the canonical prophet) is otherwise unattested; his role is structurally parallel to other royal mentors in Chronicles (Jehoiada for Joash; Hilkiah for Josiah) whose guidance restrains royal tendency toward pride. The cessation of seeking YHWH in v. 16 is the direct cause of Uzziah's fall.</p>",
    "6": "<p>Uzziah's military campaigns against Philistia — breaking down the walls of Gath, Jabneh, and Ashdod and building cities in Philistine territory — represent a period of Judahite westward expansion into the coastal plain. Iron IIb archaeological evidence from the Shephelah shows increased Judahite material culture presence at sites previously Philistine-controlled. Gath (Tell es-Safi) was attacked by Hazael of Aram c. 830 BCE (2 Kgs 12:17) and may have been weakened enough for Uzziah to exploit a generation later. Building cities in Ashdodite territory would have required establishing Judahite administrative presence and garrison infrastructure.</p>",
    "7": "<p>Divine help (<em>wayyaʿzrēhû hāʾĕlōhîm</em>) against Philistines, Arabs of Gur-baal, and Meunites is the Chronicler's theological framing for what are presumably documented military campaigns. The Meunites (from Maon, probably near Petra) appear also in 2 Chr 20:1 and 1 Chr 4:41 — a semi-nomadic group in the southeastern desert margins. Arab tribal groups of the Negev and Sinai fringe are documented in Assyrian tribute records and in the Samaria ostraca; Uzziah's reach into these territories corresponds to the period of maximum Judahite territorial extent before the Assyrian encroachments under Tiglath-pileser III.</p>",
    "8": "<p>The Ammonites giving tribute (<em>wayyittᵉnû hammaʿămonîm minḥāh lᵉʿuzziyāhû</em>) and Uzziah's fame spreading to Egypt reflects the unusual geopolitical window when both Israel (under Jeroboam II) and Judah (under Uzziah) simultaneously enjoyed strong kingship — sometimes called the 'Indian summer' of the divided monarchy before the Assyrian resurgence under Tiglath-pileser III (745 BCE onward). Assyrian records from this period show a relative absence of western campaigns (the Assyrian interregnum: 783–745 BCE, including weak kings Shalmaneser IV and Ashur-dan III), which gave Levantine kingdoms room to expand.</p>",
    "10": "<p>Uzziah's agricultural development — cisterns in the wilderness, towers in the agricultural land, vinedressers in the hills, and farmers in the plains — represents a systematic program of semi-arid land reclamation. Iron IIb Negev farmsteads at sites like Ramat Negev, Tel Arad, and Kadesh-barnea show exactly this kind of state-organized agricultural colonization. The <em>bōrôt ḥᵉṣēḇîm</em> (hewn cisterns) are archaeologically visible: plastered bell-shaped cisterns capable of holding significant water for dry-season livestock use. Uzziah's agricultural investment fits the profile of a king maximizing territorial control through civilian settlement.</p>",
    "11": "<p>Uzziah's professional army organization — under Jeiel the scribe (<em>hassôpēr</em>) and Maaseiah the officer (<em>haššôṭēr</em>) under Hananiah the royal commander (<em>miśśārê hammelek</em>) — reflects the Judahite military administrative structure. The scribe and officer together constitute a census-and-muster function; Hananiah's title as one 'of the king's commanders' places him below the supreme commander but within the professional military hierarchy. This tripartite leadership (scribe, officer, commander) resembles the Neo-Assyrian military organization where scribes track the muster, officers supervise units, and field commanders lead campaigns.</p>",
    "12": "<p>The total of 2,600 heads of fathers' houses as military officers over the fighting force of 307,500 represents the command structure for an Iron IIb Judahite army. The ratio of approximately 1 officer per 118 men is consistent with ancient Near Eastern military organization. The numbers are credible for an 8th-century Judah at the height of its territorial extent; Hezekiah's later army of similar size (2 Chr 32:6) shows these forces maintained across generations. The phrase 'who made war with mighty power' (<em>ʿōśîm milḥāmāh bᵉḵōaḥ ḥāyil</em>) identifies a professional standing force rather than a conscript levy.</p>",
    "13": "<p>The army of 307,500 who 'went to war with great power to help the king against the enemy' is presented as YHWH's gift for Uzziah's period of seeking him (v. 5). The Chronicler regularly quantifies divine blessing in military terms: large, well-organized armies are evidence of divine favor. The numbers (307,500 soldiers, 2,600 officers) are higher than the totals for some earlier Judahite armies but within the range of the Chronicler's military counts for peak kings (Abijah: 400,000 [13:3]; Jehoshaphat: up to 1,160,000 [17:14-18]). The military strength is the direct correlate of the spiritual condition of v. 5.</p>",
    "14": "<p>Uzziah's royal armory — equipping the entire army with shields, spears, helmets, coats of mail, bows, and sling stones — represents a systematic Iron IIb royal weapons program. This is the same kind of central armory the Assyrian kings maintained to standardize their imperial forces. Excavations at Tel Beer-sheba, Arad, and Lachish have recovered iron arrowheads, bronze fittings, and weapons deposits consistent with 8th-century Judahite military equipment. The list covers the full range of offensive and defensive equipment: the shields and coats of mail for close combat, bows and slings for ranged attack, spears for formation fighting.</p>",
    "16": "<p>The pivot of Uzziah's reign: 'But when he was strong, his heart was lifted up to his destruction' (<em>ûḵᵉḥezqātô gāḇah libbô ʿad-lᵉhašḥît</em>). The verb <em>gāḇah</em> (to be lifted up, proud) is the Chronicler's signature pride term, and the phrase mirrors the mechanism of Amaziah's fall in 25:19. Strength without humility is the Chronicler's formula for downfall: the same causal sequence is applied to Hezekiah's initial response to YHWH's deliverance (32:25) and to the narrative of Nebuchadnezzar in Daniel. The specific form of Uzziah's pride is trespass in the sanctuary — entering the holy place reserved for the Aaronic priesthood.</p>",
    "17": "<p>The 80 priests of YHWH who withstand Uzziah — 'valiant men' (<em>gibbôrê ḥāyil</em>, the same term for Uzziah's own soldiers) — are described as having priestly courage to confront royal transgression. Azariah the chief priest leads the confrontation. The courage required to face an angry king and declare 'you have been unfaithful' (<em>māʿaltāh</em>) in his own sanctuary echoes the prophetic confrontation pattern throughout Chronicles; but here it is the organized priesthood, not a lone prophet, performing the confrontation function. The fact that 80 priests are gathered suggests an organized priestly response, not a spontaneous intervention.</p>",
    "18": "<p>The priests' charge — 'It is not for you, Uzziah, to burn incense to YHWH, but for the priests, the sons of Aaron, who are consecrated to burn incense' — invokes the specific Aaronic priestly monopoly on incense offering (Num 16-17; the Korah rebellion narrative). Numbers 16-17 establishes through dramatic punishment (the opening earth, the fire of YHWH consuming Korah's 250 incense-offerers) that incense burning belongs exclusively to the Aaronic line. Uzziah's act parallels Saul's sacrifice at Gilgal (1 Sam 13) and Jeroboam's altar-burning (1 Kgs 12:33) — royal transgression of priestly boundaries as covenant breach.</p>",
    "19": "<p>Uzziah's anger at the priestly confrontation and the simultaneous outbreak of leprosy (<em>wayyiṣraʿ ûḇᵉʾappô ʿal-hakkōhănîm</em> — 'and he was leprous even as he was angry with the priests') is a dramatic instantaneous divine judgment. The leprosy appears on his forehead while he is holding the incense censer. The precision of location — the forehead (<em>miṣḥô</em>) — may carry priestly significance: the forehead is where the high priest wears the golden plate inscribed 'Holy to YHWH' (Ex 28:36-38); Uzziah's forehead is marked with impurity in the same place the high priest bears the mark of holiness, a visual inversion of the priestly function he attempted to usurp.</p>",
    "20": "<p>The priests 'hurried him out' (<em>wayyᵉḇahᵉlûhû miššām*</em>) once leprosy appeared — not out of fear, but because a skin-diseased person must not remain in the sanctuary. Leviticus 13-14 prescribes examination and exclusion of the leprous (<em>ṣāraʿat</em>); the sanctuary requires ritual purity. The fact that 'he also hurried to get out, because YHWH had afflicted him' shows that even Uzziah recognized the divine hand. He is cut off from the temple for the rest of his life — the sanctuary he sought to enter becomes permanently inaccessible. The punishment fits the sin: he sought unauthorized access to the holy; he is denied all access thereafter.</p>",
    "21": "<p>Uzziah's leprosy means he lives in a 'separate house' (<em>bêt hahopšît</em>) for the rest of his reign — a form of royal quarantine. The phrase <em>bêt hahopšît</em> (literally 'house of freedom/exclusion') is used elsewhere in 2 Kgs 15:5 and appears to designate a place outside the normal royal household where the king lives in quasi-exile from court functions. His son Jotham administers the royal household and judges the people in his father's stead. This regency arrangement — active co-regency due to incapacitation — explains the overlapping chronologies of Uzziah/Jotham in the Assyrian synchronisms and in the prophetic superscriptions (Isa 1:1 names both kings).</p>",
    "22": "<p>Isaiah son of Amoz wrote the acts of Uzziah 'from first to last' (<em>hārʾiššōnîm wᵉhāʾaḥărōnîm</em>) — making this the only place in Chronicles where Isaiah is cited as a historical source. Isaiah's prophetic career spanned four kings (Isa 1:1: Uzziah, Jotham, Ahaz, Hezekiah), making him the dominant prophetic voice of the Assyrian period. Isaiah's vision 'in the year that King Uzziah died' (Isa 6:1) places the divine throne-room commissioning at the moment of Uzziah's death — the earthly king's end prompting the vision of the heavenly king enthroned. The Chronicler's use of Isaiah as a historical source (cf. 2 Chr 32:32) reflects the high standing of prophetic historical writings as official records.</p>",
    "23": "<p>Uzziah is buried 'in the burial field that belonged to the kings, for they said, he is a leper.' The normal royal burial in the city of David (see 2 Chr 21:20; 24:25) is denied him because of ritual impurity. An inscription discovered on the Mount of Olives (now in the Israel Museum) reads 'Here were brought the bones of Uzziah, king of Judah. Do not open.' — a reburial notice from the Second Temple period, suggesting Uzziah's remains were eventually moved (perhaps during Herod's building program) but retained their leprous-king stigma requiring a separate burial notice. His son Jotham reigns in his place — the regency of v. 21 becoming full kingship.</p>"
  },
  "27": {
    "1": "<p>Jotham accedes at 25 and reigns 16 years in Jerusalem. His mother Jerushah daughter of Zadok connects the royal line to a priestly family (Zadok = either the Solomonic high priest's descendant or a contemporaneous priestly family from that line). The 16-year reign (c. 750–732 BCE) overlaps with the final years of Uzziah's co-regency/incapacitation and the beginning of Isaiah's ministry. Jotham's evaluation — 'he did what was right in the eyes of YHWH according to all that his father Uzziah had done' — inherits the Uzziah template but explicitly avoids the pride-failure: 'only he did not enter the temple of YHWH.'</p>",
    "2": "<p>The explicit note 'but he did not enter the temple of YHWH' reads as a pointed contrast with his father's transgression. Jotham's restraint in not repeating Uzziah's sin is highlighted by the Chronicler as a positive trait. However, the second clause — 'but the people still acted corruptly' (<em>wᵉhāʿām ʿôd mašḥîtîm</em>) — is unusual for Chronicles: it separates the king's personal fidelity from the nation's moral condition. Jotham's reign is marked by personal rectitude without corresponding national covenant renewal — a partial reform that explains his moderate evaluation.</p>",
    "3": "<p>Jotham's building program includes the upper gate of the temple of YHWH (<em>šaʿar bêt-YHWH hāʿelyôn</em>) and the wall of Ophel (<em>ḥômat hāʿōpel</em>). The Ophel is the spur of land connecting the Davidic city to the temple mount; its wall reinforcement suggests defensive investment in the vulnerable northern approach to the temple. The 'upper gate' of the temple corresponds to the gate complex through which the Levites and priests entered the sanctuary precincts — a gate mentioned in Jer 20:2; 2 Kgs 15:35. Jotham's temple-gate investment without entering the sanctuary is an ironic detail: he builds the gate but does not abuse it.</p>",
    "4": "<p>Cities and fortresses and towers in the wooded hill country (<em>bᵉhārê yᵉhûdāh ûbayᵉʿārôt</em>) point to Jotham's territorial administration in the Judahite highlands. The combination of administrative cities (<em>ʿārîm</em>), military fortresses (<em>bîrāniyyôt</em>), and watch towers (<em>miḡdālîm</em>) represents the three-tier defensive settlement system that characterized Iron IIb Judah. The hill country south of Jerusalem had significant forest coverage in the Iron Age; the Debir and Hebron highlands were likely more wooded than today, and building in forest terrain required different logistics than the Shephelah's open plains.</p>",
    "6": "<p>The Chronicler's summary evaluation — 'Jotham became mighty, because he ordered his ways before YHWH his God' (<em>wayᵉḥazzēq yôtām kî hēkîn dᵉrāḵāyw lipᵉnê YHWH ʾĕlōhāyw</em>) — uses the verb <em>ḥzq</em> (to be/become strong) that is a key term in the Chronicler's success theology. The formula 'ordered his ways before YHWH' (<em>hēkîn dᵉrāḵāyw</em>) echoes the preparation (<em>kûn</em>) vocabulary used for temple and cultic ordering — to 'prepare' or 'establish' one's ways before YHWH is the moral equivalent of cultic preparation. Jotham's strength is a direct dividend of his ordered devotion; his reign is the positive counterpoint to Uzziah's pride and Ahaz's apostasy.</p>",
    "7": "<p>Jotham's wars and ways are written in the Book of the Kings of Israel and Judah. The Syro-Ephraimite coalition begins to form in Jotham's reign (2 Kgs 15:37: 'In those days YHWH began to send Rezin and Pekah against Judah') but does not erupt into full military conflict until Ahaz's reign. Jotham thus stands at the threshold of the Assyrian crisis: his reign of ordered devotion is the last period of stability before the cataclysm of Ahaz's apostasy and the Tiglath-pileser III campaigns. The brevity of the Chronicler's account of Jotham reflects both the source limitations and the theological framing: Jotham's reign has little drama because his devotion is consistent.</p>",
    "8": "<p>The summary — 25 years old when he began to reign, 16 years as king — confirms the data of v. 1. The Assyrian Eponym Chronicle and the Ptolemaic Canon can be used to anchor the Judahite chronology in this period; Tiglath-pileser III's western campaigns (738 BCE: tribute from Menahem of Israel; 734–732 BCE: campaigns against Philistia, Israel, and Aram) provide external anchors. Jotham's death c. 732 BCE would place him as a contemporary of the Syro-Ephraimite coalition's formation and the beginning of the Assyrian intervention that his son Ahaz will weaponize.</p>",
    "9": "<p>Jotham is buried in the city of David and his son Ahaz reigns in his place. The transition from Jotham to Ahaz is one of the sharpest moral reversals in the Judahite royal narrative: from a king who 'ordered his ways before YHWH' to one who 'walked in the ways of the kings of Israel' (28:2). The Chronicler's parallel structure — Jotham's brief, positive account followed by Ahaz's extensive negative one — mirrors the pattern of Hezekiah's positive reign following Ahaz. The dynasty oscillates: Uzziah (complex), Jotham (positive), Ahaz (catastrophic), Hezekiah (exemplary).</p>"
  },
  "28": {
    "1": "<p>Ahaz accedes at 20 and reigns 16 years — making him the youngest Judahite king since David's young adulthood, and the only king whose evaluation is wholly negative without qualification in the Chronicler's account. His mother is not named (unusual in Chronicles), which may reflect deliberate editorial erasure. The 16-year reign (c. 735–715 BCE) falls during the most intense period of Assyrian western expansion: Tiglath-pileser III's campaigns (734–732), Shalmaneser V's siege of Samaria (724–722), and Sargon II's fall of Samaria (722/720). Ahaz chooses vassalage to Assyria as his survival strategy — a decision that shapes Judah's political future through Hezekiah's reign.</p>",
    "2": "<p>'He walked in the ways of the kings of Israel' — the worst evaluation the Chronicler can give a Judahite king: adopting northern apostasy. The specific charges include making molten images (<em>maṣṣēḇôt</em>) for the Baals, burning incense in the Valley of the Son of Hinnom (<em>gê ben-hinnōm</em>), and making his sons pass through fire. Child sacrifice in the Hinnom Valley (later Gehenna) is also charged against Manasseh (2 Chr 33:6) and constitutes the most extreme form of Canaanite religious adoption. The Hinnom Valley south of Jerusalem was associated with the <em>tōpet</em> (burning-place) where Molech worship occurred; Jeremiah 7:31-32 and 19:5-6 condemn this practice extensively.</p>",
    "3": "<p>Ahaz burns his sons (<em>wayyaśᵉrēp banāyw bāʾēš</em>) — child sacrifice — 'according to the abominations of the nations whom YHWH drove out before the people of Israel.' The comparative formula invokes the conquest narrative: the Canaanites were expelled for precisely these practices (Lev 18:21; 20:2-5; Deut 18:10). For a Judahite king to replicate the practices of the expelled Canaanites is the ultimate covenant irony: Israel's presence in the land is conditional on non-replication of the expelled nations' abominations, and Ahaz replicates them. The Valley of Hinnom (<em>gê-hinnōm</em>) is named as the location, confirming its identity as Jerusalem's cultic waste-disposal zone for illicit offerings.</p>",
    "4": "<p>Sacrificing and burning incense on the high places, on the hills, and under every green tree (<em>taḥat kol-ʿēṣ raʿănān</em>) is the standard Deuteronomistic formula for Canaanite-style syncretism (Deut 12:2; 1 Kgs 14:23; 2 Kgs 17:10). The 'green tree' (<em>ʿēṣ raʿănān</em>) likely refers to sacred trees or groves associated with Asherah worship, attested in ANE iconography as the stylized tree flanked by caprids (tree-of-life motif). Ahaz's worship is comprehensive and topographically distributed — not limited to one site but systematically present across the landscape, representing total cultic decentralization in opposition to the Deuteronomic centralization mandate.</p>",
    "6": "<p>Pekah son of Remaliah killed 120,000 in Judah 'in one day, mighty men of valor' (<em>ʾanšê ḥayil*</em>) 'because they had forsaken YHWH the God of their fathers.' The numbers are large (though typical of the Chronicler's military figures in absolute judgment contexts) and the theological explanation is explicit: defeat is covenant consequence, not military misfortune. The same causal grammar applies in 13:15-17 (Abijah's victory), 14:12 (Asa's victory over the Ethiopians), and throughout: military outcomes are theological verdicts. Pekah's stated reason for success is Judah's apostasy — YHWH fights against his own people through Israel as the instrument of discipline.</p>",
    "7": "<p>Zichri of Ephraim kills Maaseiah the king's son, Azrikam the commander of the palace, and Elkanah the second-in-command (<em>mišneh hammelek</em>) — three high-ranking palace officials. The detail of killing the king's son (not Ahaz himself) and two senior court officials suggests targeted leadership decapitation: the Israelite forces are not merely routing an army but destroying Judahite administrative capacity. The 'second-in-command of the king' (<em>mišneh hammelek</em>) is attested as a formal title in ANE administrative texts; the title appears in the Elephantine papyri and Assyrian court records.</p>",
    "8": "<p>The 200,000 captives taken by Israel — 'their brothers' (<em>ʾăḥêhem</em>), the text emphasizes — along with great plunder brought to Samaria constitutes the largest captive-taking between Israelites and Judahites in the biblical record. The 'brothers' language is pointed: northerners enslaving southerners violates the covenant solidarity between the twelve tribes. The scale of the spoil (women, sons, daughters, plus much plunder) is consistent with the massive population disruptions documented in Neo-Assyrian campaign records of the same period; the Assyrians regularly deported hundreds of thousands from conquered territories, and their Israelite clients apparently learned the practice.</p>",
    "9": "<p>Oded the prophet in Samaria confronts the returning northern army with a prophetic judgment oracle. This episode is unique in Chronicles: an unnamed prophet from the north acts righteously to restrain northern troops from enslaving their Judahite brothers. YHWH's wrath against Judah was the instrument of Judah's punishment, Oded argues, but the northerners have gone too far (<em>wᵉʿattāh ḇᵉnê-yᵉhûdāh wîrûšālaim ʾattōm ʾōmrîm liḵbōš laʿăḇādîm wᵉlišᵉpāḥôt</em>). The northern army is being used by God but does not have divine authorization to enslave God's people permanently — a distinction between divine permission and divine sanction.</p>",
    "10": "<p>Oded's charge — 'Are there not sins against YHWH your God with you?' — reminds the victorious northern army of their own covenant unfaithfulness. The northern kingdom's apostasy (golden calves, Asherah, Baal) is the implicit charge; having been instruments of divine judgment against Judah does not grant them righteousness. The same argument appears implicitly in Isaiah 10:5-15: Assyria is YHWH's rod of anger, but Assyria's own pride in its power is itself a sin deserving punishment. Instruments of judgment are not exempt from judgment.</p>",
    "11": "<p>Oded commands the return of the captives: 'return the captives you have taken from your brothers, for the fierce wrath of YHWH is upon you' (<em>kî-ḥărôn ʾap-YHWH ʿălêḵem</em>). The threat of divine anger falling on the captors reverses the normal victor-captive dynamic: the militarily powerful northern army is now in a position of moral vulnerability. The word <em>ḥărôn</em> (burning anger, from <em>ḥrh</em>) is the strongest anger vocabulary in Hebrew; its object has shifted from Judah (vv. 5-8, the punishment) to Israel (vv. 9-11, the overcorrection).</p>",
    "12": "<p>Four named leaders of Ephraim support Oded's position against the returning commanders: Azariah son of Johanan, Berechiah son of Meshillemoth, Jehizkiah son of Shallum, and Amasa son of Hadlai. These are civic/tribal leaders (<em>rāšê bᵉnê-ʾeprayim</em>) rather than priests or prophets — laypeople responding to prophetic instruction. Their names are theophoric (incorporating YHWH): Azariah ('YHWH has helped'), Berechiah ('YHWH blesses'), Jehizkiah ('YHWH strengthens') — ironic given the northern kingdom's official departure from YHWH-worship. Individual northerners retain covenant names and act on covenant principles even within an apostate kingdom.</p>",
    "13": "<p>The Ephraimite leaders argue the captives cannot be brought in: 'You must not bring the captives here, for it will bring us guilt before YHWH in addition to our sins and our guilt, for great is our guilt, and there is fierce wrath against Israel.' The acknowledgment of existing northern guilt (<em>ʾašmāh</em>) and accumulated sin, combined with awareness that adding enslavement of Judahite brothers would compound the indictment, shows a degree of theological self-awareness within northern Israel. The episode presents the northerners as capable of moral reasoning and covenant sensitivity, complicating any simple Chronicler-as-southern-partisan reading.</p>",
    "14": "<p>The soldiers abandon (<em>wayyaʿazbû</em>) the captives and spoil before the commanders and all the assembly (<em>haqQāhāl</em>). The use of <em>qāhāl</em> (assembly) for the gathered northern military is significant: it is the Chronicler's standard term for the covenant assembly of Israel (frequently used for temple dedication, Passover gatherings, etc.). Even the northern army's deliberative gathering uses the covenant-community vocabulary, suggesting the Chronicler does not write off the north as entirely outside the covenant community.</p>",
    "15": "<p>The specific named men who 'clothed the naked, gave sandals, food, drink, oil, carried the feeble on donkeys, and brought them to Jericho' performs a comprehensive humanitarian act that resembles later Good Samaritan logic (Luke 10:33-35 uses similarly comprehensive care language). Jericho is the natural crossing point for returning Judahites from Ephraim: the Jordan fords near Jericho were the standard route. The released captives are 'their brothers' (<em>ʾăḥêhem</em>) five times in this section — the sibling language is the theological center of the episode's ethic.</p>",
    "17": "<p>The Edomites invaded Judah and carried away captives (<em>wayyiśbû šiḇyāh</em>) while Ahaz was already under pressure from Aram and Israel. The simultaneous Edomite and Philistine attacks (vv. 17-18) while the Syro-Ephraimite coalition pressed from the north represents a coordinated opportunistic assault on Ahaz's weakened kingdom — the collapse of Judahite military capacity inviting border raids from all sides. Edomite aggression in this period (c. 735-715 BCE) presages the Edomite occupation of the Negev that becomes permanent after the Babylonian destruction (Obadiah; Ezek 35).</p>",
    "18": "<p>The Philistines raided the cities of the Shephelah and the Negeb — taking Beth-shemesh, Aijalon, Gederoth, Soco, Timnah, and Gimzo. The list represents Judah's western lowland defensive perimeter: the Shephelah cities that protected the highland approaches to Jerusalem. Beth-shemesh and Timnah (Tell Batash) are excavated sites with Iron IIb destruction levels; Soco and Aijalon guard valley passes. The loss of the Shephelah to Philistine control reverses Uzziah's expansion (26:6) and represents a severe territorial contraction. Archaeological surveys of the Shephelah show reduced Judahite settlement in the late 8th century, consistent with this Philistine pressure.</p>",
    "19": "<p>'For YHWH humbled (<em>hikniʿ</em>) Judah because of Ahaz king of Israel' — the Chronicler calls Ahaz 'king of Israel' (not 'king of Judah') at this moment, a pointed theological demotion: Ahaz has so fully replicated northern apostasy that he is functionally a northern king. The verb <em>hiknîʿ</em> (to humble, bring low) is the causative of the covenant-renewal vocabulary: the same root is used for Manasseh's humbling before YHWH (33:12) and for the ideal posture of covenant return. Here YHWH humbles Judah through enemy attack as the covenantal consequence of Ahaz's 'unbridled unfaithfulness' (<em>pāraʿ pᵉraʿôt</em> — literally 'he let loose/was unrestrained in unfaithfulness').</p>",
    "20": "<p>Tiglath-pileser III of Assyria came and distressed (<em>wayyāṣar-lô</em>) Ahaz rather than helping him. The Assyrian king's campaign in the region (734–732 BCE) is confirmed by his own annals: Tiglath-pileser lists tribute received from Ahaz (<em>Ia-u-ha-zi of Judah</em>), Hanno of Gaza, and others after his Philistine campaign. The irony the Chronicler emphasizes is that Ahaz solicited Assyrian help but received Assyrian exploitation: Tiglath-pileser took the tribute and then continued his campaigns for Assyrian advantage, not Ahaz's protection. The 'helper' became an overlord — the Assyrian suzerainty Ahaz purchased was permanent subjugation.</p>",
    "21": "<p>Ahaz stripped the temple, palace, and princes to pay Tiglath-pileser but it 'did not help him' (<em>wᵉlōʾ lᵉʿezrāh lô</em>). The despoliation of the temple treasury to pay foreign tribute is a recurring Judahite crisis move (Asa in 16:2; Joash in 24:23; Hezekiah forced to strip the temple doors in 2 Kgs 18:16). Each instance represents sanctuary resources being diverted from YHWH's service to imperial tribute — the temple's wealth protecting the king rather than honoring God. The Chronicler's judgment 'it did not help him' is the covenant verdict: human resources substituted for divine dependence fail.</p>",
    "22": "<p>In his distress Ahaz 'became yet more faithless to YHWH — this same King Ahaz' (<em>wayyōsep lim-ʿôl baYHWH hûʾ hammelek ʾāḥāz</em>). The emphatic pronoun 'this same King Ahaz' (<em>hûʾ hammelek</em>) is a Chronicler's rhetorical device for heightening the indictment — pointing to the person as the one responsible for the escalating apostasy. The pattern is the inverse of the usual Chronicles retribution: instead of distress producing repentance (as with Manasseh in 33:12-13), distress produces escalating faithlessness. Ahaz is the anti-Manasseh: a king who, under covenantal pressure, doubles down on covenant violation rather than returning.</p>",
    "24": "<p>Ahaz gathered the temple vessels, smashed them (<em>wayyᵉqaṣṣēṣ ʾet-kᵉlê bêt-hāʾĕlōhîm</em>) and sealed the doors of the temple of YHWH. The sealing of the temple doors is the most extreme sacrilege Ahaz commits: not merely neglecting the temple or redirecting its revenues, but actively closing and sealing the sanctuary. The Chronicler presents this as the nadir of Ahaz's apostasy — the same act that Hezekiah's first deed reverses (29:3: 'he opened the doors of the temple'). The temple-closing is the hinge between apostasy and reform across the reigns of Ahaz and Hezekiah.</p>",
    "25": "<p>Ahaz built altars in every corner of Jerusalem and made high places in every city of Judah to burn incense to other gods — provoking YHWH to anger (<em>wayyakʿēs ʾet-YHWH ʾĕlōhê ʾăḇōtāyw</em>). The comprehensive geographic spread of the altars — 'every corner of Jerusalem... every city of Judah' — presents Ahaz's apostasy as the systematic anti-mission to YHWH-worship, constructing a counter-temple system. The verb <em>kʿs</em> (to provoke to anger/vex) appears regularly in the Deuteronomistic History for idolatry; the Chronicler adopts the vocabulary here, which is less common in Chronicles than in Kings.</p>",
    "26": "<p>Ahaz's acts are written in the Book of the Kings of Judah and Israel. The Chronicler's source citation for Ahaz is identical in form to citations for other kings but carries heightened irony: Ahaz's reign, which the Chronicler has presented as the model of apostasy, generated enough historical activity to fill the official royal records. The existence of an official record does not confer legitimacy; the Chronicler cites the source and lets the content of his account provide the theological verdict.</p>",
    "27": "<p>Ahaz is buried 'in the city, in Jerusalem, but they did not bring him into the tombs of the kings of Israel' — denied royal tomb burial is the Chronicler's final judgment gesture, parallel to the denied burial of Jehoram (21:20) and Joash (24:25). The specific formulation 'tombs of the kings of Israel' (<em>qiḇrê malᵉḵê yiśrāʾēl</em>) — rather than 'kings of Judah' — uses the inclusive 'Israel' rather than the divisive 'Judah,' perhaps suggesting that Ahaz denied the proper tomb because he had ceased to function as a legitimate covenant king. His son Hezekiah reigns in his place — the most dramatic reversal in the entire Judahite royal sequence.</p>"
  }
}

def main():
    c = load_comm('mkt-context', '2chronicles')
    merge_comm(c, PATCH)
    save_comm('mkt-context', '2chronicles', c)
    count = sum(len(v) for v in PATCH.values())
    print(f'2chronicles mkt-context ch25-28 patch: wrote {count} verses')

if __name__ == '__main__':
    main()
